CREATE TABLE `courses` (
  `course_id` int NOT NULL AUTO_INCREMENT,
  `course_code` varchar(20) NOT NULL,
  `course_title` varchar(200) NOT NULL,
  `description` text,
  `units` int NOT NULL,
  `department` varchar(50) NOT NULL,
